cd /tmp/sv-eb95778feb214d4a987fa272be4e32b4/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> (requested, resolved)
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    if k in b and k in a:
        if b[k][1] != a[k][1]:
            changes.append((proj, fw, pkg, b[k][1], a[k][1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, a[k][1]))
    elif k in a and k not in b:
        changes.append((proj, fw, pkg, '-', a[k][1], 'Added'))
    elif k in b and k not in a:
        changes.append((proj, fw, pkg, b[k][1], '-', 'Removed'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
else:
    print('  None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

